const jobId = $('Extract Fields').item.json.job_id;
const channelId = $('Extract Fields').item.json.channel_id;
const userId = $('Extract Fields').item.json.user_id;
const audioUrl = ($('Extract Fields').item.json.audio_url || '').trim();
const heygenApiKey = ($env.HEYGEN_API_KEY || '').trim();
const avatarId = (($('Extract Fields').item.json.avatar_id || '') || ($env.HEYGEN_AVATAR_ID || '')).trim();
const kstDate = new Intl.DateTimeFormat('en-CA', {
  timeZone: 'Asia/Seoul',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
}).format(new Date()).replace(/-/g, '');
const videoFilename = `${kstDate}-${jobId}.mp4`;

try {
  if (!heygenApiKey) {
    throw new Error('HEYGEN_API_KEY is not configured');
  }
  if (!avatarId) {
    throw new Error('avatar_id is not configured');
  }
  if (!audioUrl) {
    throw new Error('audio_url is required');
  }

  const audioResp = await this.helpers.httpRequest({
    method: 'GET',
    url: audioUrl,
    encoding: null,
    returnFullResponse: true,
    timeout: 300000,
  });
  const audioBytes = Buffer.isBuffer(audioResp.body)
    ? audioResp.body
    : Buffer.from(audioResp.body || '');
  if (!audioBytes.length) {
    throw new Error('audio download returned empty body');
  }

  const uploadData = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://upload.heygen.com/v1/asset',
    headers: { 'X-Api-Key': heygenApiKey },
    formData: {
      file: {
        value: audioBytes,
        options: {
          filename: 'audio.wav',
          contentType: 'audio/wav',
        },
      },
    },
    json: true,
    timeout: 300000,
  });

  const assetId = uploadData.data?.id || uploadData.asset_id;
  if (!assetId) {
    throw new Error(`HeyGen upload returned no asset_id: ${JSON.stringify(uploadData)}`);
  }

  const videoBody = {
    video_inputs: [{
      character: {
        type: 'avatar',
        avatar_id: avatarId,
        avatar_style: 'normal',
      },
      voice: {
        type: 'audio',
        audio_asset_id: assetId,
      },
    }],
    dimension: { width: 1280, height: 720 },
  };

  const videoData = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.heygen.com/v2/video/generate',
    headers: {
      'X-Api-Key': heygenApiKey,
      'Content-Type': 'application/json',
    },
    body: videoBody,
    json: true,
    timeout: 300000,
  });

  const videoId = videoData.data?.video_id;
  if (!videoId) {
    throw new Error(`HeyGen create video returned no video_id: ${JSON.stringify(videoData)}`);
  }

  const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
  const maxRetries = 40;
  const intervalMs = 15000;
  let videoUrl = '';
  let status = 'processing';

  for (let i = 0; i < maxRetries; i++) {
    await sleep(intervalMs);
    const pollData = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://api.heygen.com/v1/video_status.get?video_id=${encodeURIComponent(videoId)}`,
      headers: { 'X-Api-Key': heygenApiKey },
      json: true,
      timeout: 30000,
    });

    status = pollData.data?.status || 'processing';
    if (status === 'completed') {
      videoUrl = pollData.data?.video_url || '';
      break;
    }
    if (status === 'failed') {
      break;
    }
  }

  return {
    json: {
      ok: status === 'completed' && !!videoUrl,
      completed: status === 'completed' && !!videoUrl,
      status,
      video_url: videoUrl,
      video_id: videoId,
      video_filename: videoFilename,
      avatar_id: avatarId,
      job_id: jobId,
      channel_id: channelId,
      user_id: userId,
    },
  };
} catch (e) {
  const message = e && e.message ? e.message : String(e);
  return {
    json: {
      ok: false,
      completed: false,
      status: 'failed',
      error: message,
      video_url: '',
      video_filename: videoFilename,
      avatar_id: avatarId,
      job_id: jobId,
      channel_id: channelId,
      user_id: userId,
    },
  };
}
